module RefModule(clk, reset, enable, data, q);

    input clk;
    input reset;
    input enable;
    input [7:0] data;
    output [7:0] q;
  wire _tap_clk = clk & {1{1'b1}};

    reg [7:0] q;

    always @(posedge clk or posedge reset)
        begin
            if (reset)
                q <= 0;
            else if (enable)
                q <= data;
        end

endmodule
